// components/Certifications.tsx
import React, { useState } from 'react';
import { CERTIFICATIONS } from '../constants';

interface Certificate {
  name: string;
  issuer?: string;
  year?: string;
  details?: string;
  image?: string;
}

const Certifications: React.FC = () => {
  const [selectedCert, setSelectedCert] = useState<Certificate | null>(null);

  const openModal = (cert: Certificate) => {
    setSelectedCert(cert);
  };

  const closeModal = () => {
    setSelectedCert(null);
  };

  return (
    <div>
      {CERTIFICATIONS.map((cert, index) => (
        <button
          key={index}
          onClick={() => openModal(cert)}
          className="bg-gray-200 hover:bg-gray-300 text-gray-800 font-bold py-2 px-4 rounded focus:outline-none focus:shadow-outline mb-2"
        >
          {cert.name}
        </button>
      ))}

      {selectedCert && (
        <div className="fixed top-0 left-0 w-full h-full bg-black bg-opacity-50 flex items-center justify-center">
          <div className="bg-white rounded-lg p-8 max-w-lg relative">
            <button className="absolute top-2 right-2 text-gray-600 hover:text-gray-800" onClick={closeModal}>
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
            <h2 className="text-2xl font-semibold mb-4">{selectedCert.name}</h2>
            {selectedCert.image && (
              <img src={selectedCert.image} alt={selectedCert.name} className="w-full mb-4 rounded" />
            )}
            {selectedCert.issuer && <p>Issuer: {selectedCert.issuer}</p>}
            {selectedCert.year && <p>Year: {selectedCert.year}</p>}
            {selectedCert.details && (
              <p className="whitespace-pre-line break-words">Details: {selectedCert.details}</p>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default Certifications;
